INSERT INTO `career_recommendation` (`field`, `domain`, `technical_skill`, `best_colleges`, `core_subjects`, `recommended_books`, `online_courses`, `youtube_channels`, `websites`, `placement_info`, `job_roles`, `job_status`, `salary_info`, `training_internship`, `career_path`, `certifications`) VALUES
('Engineering', 'Mechanical Engineering', 'AutoCAD', 'IIT Bombay, IIT Delhi, BITS Pilani, NIT Trichy', 'Engineering Mechanics, Thermodynamics, Strength of Materials', 'R.S. Khurmi - Engg Mechanics, P.K. Nag - Thermodynamics', 'Coursera: AutoCAD Basics, Udemy: AutoCAD Advanced', 'SourceCAD, CAD in Black, NPTEL India', 'https://nptel.ac.in, https://autodesk.com', '85-95% in top colleges, core company placements available', 'Design Engineer, CAD Engineer, Maintenance Engineer', 'Moderate in India, High demand abroad', '₹3-5 LPA starting, ₹10+ LPA with experience', 'BHEL, ISRO, Tata, DRDO summer training options', 'B.Tech > Intern > CAD Expert > Senior Engineer > Project Manager', 'AutoCAD Certification, SolidWorks CSWA, Six Sigma Green Belt'),
('Engineering', 'Mechanical Engineering', 'SolidWorks', '[\"IIT Bombay\", \"IIT Madras\", \"IIT Delhi\", \"BITS Pilani\", \"NIT Trichy\", \"VIT Vellore\", \"DTU\"]', '[\"Engineering Mechanics\", \"Thermodynamics\", \"Fluid Mechanics\", \"Machine Design\", \"Manufacturing Technology\", \"Strength of Materials\", \"Heat Transfer\", \"CAD/CAM\"]', '[\"Engineering Mechanics - R.S. Khurmi\", \"Theory of Machines - S.S. Rattan\", \"Strength of Materials - Timoshenko\", \"Fundamentals of Thermodynamics - Sonntag\", \"Mechanical Engineering Design - Shigley\", \"SolidWorks 2022 Black Book - Gaurav Verma\"]', '[\"SolidWorks Essentials - LinkedIn Learning\", \"SolidWorks Complete Course - Udemy\", \"MIT Mechanical Engineering - MIT OCW\", \"CAD & Digital Manufacturing - Coursera\"]', '[\"SourceCAD - https://www.youtube.com/c/SourceCAD\", \"CAD CAM Tutorial - https://www.youtube.com/c/CADCAMTUTORIAL\", \"NYC CNC - https://www.youtube.com/c/nyccnc\", \"Engineering Explained - https://www.youtube.com/user/EngineeringExplained\", \"SolidWorks - https://www.youtube.com/c/SolidWorks\"]', '[\"https://www.solidworks.com\", \"https://grabcad.com\", \"https://mechanicalc.com\", \"https://engineeringtoolbox.com\", \"https://edx.org\"]', 'Top recruiters include Tata Motors, Mahindra, Bosch, Maruti Suzuki, L&T, ISRO, and DRDO. Roles: CAD Engineer, Product Development Engineer, Project Engineer.', '[\"CAD Designer\", \"SolidWorks Specialist\", \"Mechanical Design Engineer\", \"Simulation Analyst\"]', 'High demand in manufacturing, automotive, aerospace, robotics sectors.', 'Starting: ₹3.5–5.5 LPA, Mid: ₹6–9 LPA, Senior: ₹10–18+ LPA, Abroad: $60K–$100K+', 'Internships at L&T, BHEL, Tata, Maruti, Siemens. SolidWorks Certification & short-term courses recommended.', 'CAD Engineer → Design Lead → Project Manager → R&D Head → Consultant/Entrepreneur', '[\"CSWA/CSWP\", \"Autodesk Certified\", \"CAD/CAM Certificate\", \"Six Sigma\", \"PMP\"]'),
('Engineering', 'Mechanical Engineering', 'MATLAB', 'IIT Bombay, IIT Delhi, IIT Madras, IIT Kanpur, IIT Kharagpur, BITS Pilani, NIT Trichy, IIIT Hyderabad, DTU Delhi, VIT Vellore', 'Thermodynamics, Fluid Mechanics, Strength of Materials, Theory of Machines, Heat Transfer, Engineering Mechanics, Dynamics & Vibrations, Control Systems, Robotics, Mechatronics', 'Engineering Thermodynamics by P.K. Nag, Theory of Machines by R.S. Khurmi, Strength of Materials by S. Ramamrutham, MATLAB for Engineers by Holly Moore, MATLAB by Stormy Attaway, Control Systems Engineering by Nagrath & Gopal', 'MATLAB for Mechanical Engineers – Udemy, Introduction to MATLAB – MathWorks, MATLAB and Simulink Training – Coursera, FEA using MATLAB – NPTEL', 'NPTEL Mechanical Engineering - https://www.youtube.com/@nptelhrd, Learn Engineering - https://www.youtube.com/c/LearnEngineering, MATLAB - https://www.youtube.com/user/MATLAB, Gate Smashers - https://www.youtube.com/c/GateSmasher, Engineering Funda - https://www.youtube.com/c/EngineeringFunda, Sanfoundry - https://www.youtube.com/@Sanfoundry', 'https://www.mathworks.com, https://www.nptel.ac.in, https://www.edx.org, https://www.coursera.org, https://www.mechanicalc.com, https://www.simscale.com, https://www.engineersedge.com', 'Top colleges like IITs, NITs, and BITS offer excellent placement opportunities. Companies hiring MATLAB-skilled Mechanical Engineers include ISRO, Bosch, GE, TATA Motors, L&T, Siemens, Honeywell, and Maruti Suzuki.', 'Simulation Engineer, CAE Analyst, Control Systems Engineer, Robotics Engineer, Mechatronics Developer, R&D Engineer, Automation Engineer', 'Active & Evolving – Growing demand in automation, AI-integrated systems, and Industry 4.0 applications', 'Fresher: ₹3.5 – ₹6 LPA; Mid-Level (2–4 yrs): ₹6 – ₹10 LPA; Senior (5–10 yrs): ₹10 – ₹18 LPA; Abroad: ₹20+ LPA', 'ISRO, BHEL, NTPC, TATA Motors, Maruti Suzuki, Ashok Leyland; also available on Internshala, LetsIntern, AICTE portal', 'Graduate Engineer Trainee → Junior Engineer → Simulation/Design Engineer → Project Lead → R&D Head or Specialized Roles → Postgraduate (M.Tech/MS)', 'MATLAB Certification (MathWorks), FEA/CAE with ANSYS, Automotive Engineering (Coursera/NPTEL), Control Systems (edX), Robotics (Coursera - Penn State)'),
('Engineering', 'Mechanical Engineering', 'CNC Programming', 'IIT Bombay, IIT Madras, IIT Delhi, IIT Kanpur, BITS Pilani, NIT Trichy, DTU, VIT, Manipal Institute of Technology, COEP Pune', 'Manufacturing Technology, Machine Design, Material Science, Thermodynamics, CAD/CAM, Mechatronics, Engineering Mechanics, Control Systems', 'Manufacturing Engineering and Technology – Serope Kalpakjian, CNC Programming Handbook – Peter Smid, CAD/CAM – Mikell Groover, Introduction to Mechatronics – David Alciatore, Fundamentals of Modern Manufacturing – Mikell Groover', 'Coursera:CNC Programming with Fusion 360, Udemy:CNC Programming Basics & G-code, edX:Digital Manufacturing & Design, Skill-Lync:CNC & Industrial Automation', 'NYCCNC:https://www.youtube.com/user/saunixcomp, Engineering Explained:https://www.youtube.com/user/EngineeringExplained, TechTrixInfo:https://www.youtube.com/user/techtrixinfo, CNC Training Centre:https://www.youtube.com/c/CNCTrainingCentre, MechStuff:https://www.youtube.com/c/MechStuff', 'https://www.coursera.org, https://www.autodesk.com, https://www.mastercam.com, https://www.cnccookbook.com, https://www.edx.org, https://www.skill-lync.com, https://nptel.ac.in', 'Top mechanical engineering colleges have tie-ups with Tata Motors, L&T, Mahindra, Bosch, Ashok Leyland, GE, ISRO, DRDO. Students with CNC skills are placed in manufacturing and automation roles.', 'CNC Programmer, CNC Operator, Manufacturing Engineer, Production Supervisor, CAM Engineer', 'High demand in manufacturing & automation sector. Key locations: Pune, Bangalore, Chennai, Ahmedabad, Hyderabad', 'Fresher: ₹20,000 - ₹30,000/month; Mid-Level: ₹35,000 - ₹50,000/month; Experienced: ₹60,000 - ₹90,000/month', 'BHEL, HAL, Tata Steel, ISRO, Maruti Suzuki, L&T. Also available via Internshala, LetsIntern, AICTE internship portal', 'CNC Operator → CNC Programmer → CAM Engineer → Production Head → Consultant or R&D Engineer', 'Mastercam Certification, AutoDesk Certified CAM Professional, Siemens NX CAM, Coursera/edX CNC Certificates, CMfgT'),
('Engineering', 'Mechanical Engineering', 'Thermodynamics', 'IIT Bombay, IIT Madras, IIT Kharagpur, IIT Roorkee, BITS Pilani, NIT Trichy, DTU, Jadavpur University, Anna University, COEP Pune', 'Thermodynamics, Heat and Mass Transfer, Applied Thermodynamics, Fluid Mechanics, Internal Combustion Engines, Power Plant Engineering, Refrigeration and Air Conditioning, Energy Systems', 'Engineering Thermodynamics – P.K. Nag, Fundamentals of Engineering Thermodynamics – Moran & Shapiro, Heat and Mass Transfer – R.K. Rajput, Thermodynamics: An Engineering Approach – Yunus A. Çengel, Internal Combustion Engines – V. Ganesan', 'NPTEL:Thermodynamics by IIT Kharagpur, Coursera:Introduction to Thermodynamics, edX:Thermodynamics by University of Michigan, Udemy:Thermodynamics for Engineers, MIT OCW:Thermal Fluids Engineering', 'Learn Engineering:https://www.youtube.com/c/LearnEngineering, NPTELHRD:https://www.youtube.com/c/nptelhrd, Engineering Explained:https://www.youtube.com/user/EngineeringExplained, MIT OCW:https://www.youtube.com/user/MIT, MechZone:https://www.youtube.com/c/MechZone', 'https://nptel.ac.in, https://ocw.mit.edu, https://www.coursera.org, https://www.edx.org, https://mechanicalbase.com, http://thermodynamicsweb.com', 'Top colleges place students in thermal and energy-based roles at BHEL, NTPC, ONGC, ISRO, DRDO, Tata Power, GE Power, Indian Railways and utilities. Strong demand in public and private sectors.', 'Thermal Engineer, HVAC Engineer, Energy Analyst, Power Plant Engineer, Research Engineer', 'Consistent demand in power, HVAC, automobile, aerospace, and utility sectors. Key cities: Bangalore, Hyderabad, Chennai, Pune, Noida', 'Fresher: ₹25,000 - ₹35,000/month; Mid-Level: ₹40,000 - ₹60,000/month; Senior: ₹70,000 - ₹1,00,000/month', 'BHEL, Tata Power, Thermax, NTPC, ISRO, ONGC; Apply via Internshala, AICTE Internship Portal, and official sites', 'Junior Thermal Engineer → HVAC/Power Plant Engineer → Lead Analyst → R&D/Design Engineer → Energy Manager/Consultant', 'Energy Manager Certification (BEE), HVAC Design Certificate, ANSYS Simulation Certificate, Thermodynamics Certificate from Coursera/edX, Certified Energy Auditor (CEA)'),
('Engineering', 'Civil Engineering', 'AutoCAD Civil 3D', 'IIT Roorkee, IIT Bombay, IIT Kharagpur, IIT Madras, NIT Trichy, NIT Surathkal, BITS Pilani, DTU, COEP Pune, Anna University', 'Transportation Engineering, Surveying and Geomatics, Highway and Railway Engineering, Construction Planning and Management, Remote Sensing & GIS, CAD for Civil Engineers, Land Use and Infrastructure Planning', 'Civil 3D Essentials – Eric Chappell, Surveying Vol 1 & 2 – B.C. Punmia, Transportation Engineering – S.K. Khanna & Justo, Planning and Design of Engineering Systems – Graeme Dandy, AutoCAD Civil 3D Tutorials – Autodesk Official Training Guides', 'Coursera:CAD & Digital Land Surveying, Udemy:AutoCAD Civil 3D Complete Guide, Skill-Lync:Road Design using Civil 3D, NPTEL:Geomatics Engineering, Autodesk Learn Platform:AutoCAD Civil 3D', 'CAD in Hindi:https://www.youtube.com/@cadhindi, Skill-Lync:https://www.youtube.com/c/SkillLync, The Civil Engineer:https://www.youtube.com/c/TheCivilEngineer, CADLearning:https://www.youtube.com/@cadlearning, Autodesk Infrastructure Solutions:https://www.youtube.com/@AutodeskCivil', 'https://www.autodesk.com/products/civil-3d, https://knowledge.autodesk.com, https://skill-lync.com, https://nptel.ac.in, https://theconstructor.org', 'Students skilled in AutoCAD Civil 3D are hired by top infrastructure and design companies like AECOM, L&T, Tata Projects, Shapoorji Pallonji, Jacobs, Arcadis, and public departments like PWD, DMRC, and CPWD.', 'CAD Engineer (Civil), Highway Design Engineer, GIS and Land Survey Specialist, Site Layout Engineer, Roadway Design Engineer, BIM Infrastructure Technician', 'High demand due to rapid infrastructure growth, smart city and highway development. Cities with most opportunities: Delhi NCR, Bangalore, Hyderabad, Pune, Ahmedabad.', 'Fresher: ₹20,000 – ₹35,000/month; Mid-Level: ₹40,000 – ₹60,000/month; Senior: ₹75,000 – ₹1,10,000/month', 'Autodesk India, AECOM, L&T, Skill-Lync, Afcons, Bentley Systems; Apply via AICTE Internship Portal, Internshala, Autodesk Learning Hub', 'CAD Technician → Civil CAD Engineer → Civil 3D Designer → Infrastructure Modeler → Senior Highway/BIM Manager', 'Autodesk Certified Professional: Civil 3D for Infrastructure, Skill-Lync Civil 3D Road Design Certificate, Bentley BIM + CAD Certificate, Coursera/edX Civil Infrastructure Design Certificate'),
('Engineering', 'Civil Engineering', 'Revit', 'IIT Roorkee, IIT Bombay, IIT Madras, BITS Pilani, NIT Surathkal, NIT Trichy, DTU, COEP Pune, Anna University, Jamia Millia Islamia', 'Building Planning and Drawing, Construction Materials, Design of RC Structures, Surveying and Geomatics, Construction Project Management, Architectural Design, Building Information Modeling (BIM), Structural Engineering & Design', 'Mastering Autodesk Revit – Eddy Krygiel, Building Construction – B.C. Punmia, Architectural Graphics – Francis D.K. Ching, Design of RC Structures – S. Ramamrutham, Construction Planning and Management – P.S. Gahlot & B.M. Dhir', 'Coursera:BIM Fundamentals for Engineers, Udemy:Learn Revit from Scratch, Skill-Lync:BIM in Civil Engineering, LinkedIn Learning:Revit 2024 Essential Training, NPTEL:Building Technology and BIM', 'Revit Pure:https://www.youtube.com/c/RevitPure, The BIM Hub:https://www.youtube.com/@TheBIMHub, Autodesk Building Solutions:https://www.youtube.com/user/AutodeskBuilding, Balkan Architect:https://www.youtube.com/c/BalkanArchitect, Civil Guruji:https://www.youtube.com/c/CivilGuruji', 'https://www.autodesk.com/revit, https://bimsmith.com, https://revitcity.com, https://nptel.ac.in, https://skill-lync.com', 'Revit skills help in placement at L&T, Shapoorji Pallonji, Tata Projects, AECOM, WSP, Atkins, TCE, Jacobs. Also in architectural consultancies and BIM firms like Pinnacle Infotech, XS CAD.', 'BIM Modeler, Revit Technician, BIM Coordinator, Architectural Draftsman, Structural BIM Engineer', 'Very high demand due to BIM adoption across India. Jobs available in real estate, infrastructure, MEP, and smart city projects. Locations: Delhi NCR, Pune, Bangalore, Hyderabad, Mumbai', 'Fresher: ₹25,000 - ₹40,000/month; Mid-Level: ₹45,000 - ₹65,000/month; Senior: ₹80,000 - ₹1,20,000/month', 'L&T, AECOM, Tata Consulting Engineers, Pinnacle Infotech, Simplex Infra, DesignTech Systems; Apply via Internshala, AICTE Portal, and Autodesk Learning Hub', 'Revit Draftsman → BIM Modeler → BIM Coordinator → BIM Manager/Lead Designer → Project Manager/BIM Consultant', 'Autodesk Certified Professional: Revit for Structural Design, BuildingSMART BIM Certification, Revit MEP/Structure/Architecture Certification, Skill-Lync Revit Professional Course, Coursera BIM Certificates'),
('Engineering', 'Civil Engineering', 'STAAD Pro(Structural Analysis and Design Software)', 'IIT Roorkee, IIT Bombay, IIT Madras, IIT Kharagpur, NIT Surathkal, NIT Trichy, BITS Pilani, DTU, COEP Pune, Jadavpur University', 'Structural Analysis, RCC Design, Steel Structure Design, Construction Materials, Engineering Mechanics, Foundation Engineering, Earthquake Engineering, Finite Element Analysis', 'Limit State Design of Reinforced Concrete – B.C. Punmia, Design of Steel Structures – S.K. Duggal, Structural Analysis – R.C. Hibbeler, Reinforced Concrete Design – N. Krishna Raju, STAAD Pro Manual & Tutorials – Bentley Institute', 'Skill-Lync:STAAD.Pro for Civil Engineers, Udemy:STAAD Pro Complete Course, Coursera:Structural Engineering Specialization, NPTEL:Structural Design, Bentley Learn Server:STAAD Pro Training', 'GATE Academy Civil:https://www.youtube.com/c/TheGateAcademyCivil, Er. J.K. Singh STAAD Pro:https://www.youtube.com/c/ErJKSingh, Civil Engineers Academy:https://www.youtube.com/c/CivilEngineersAcademy, Skill-Lync:https://www.youtube.com/c/SkillLync, Bentley Education:https://www.youtube.com/c/BentleyEducation', 'https://www.bentley.com, https://learn.bentley.com, https://skill-lync.com, https://nptel.ac.in, https://theconstructor.org', 'STAAD Pro knowledge improves placement chances in L&T Construction, TCE, Shapoorji Pallonji, Gammon India, Tata Projects, and structural design firms like WSP, AECOM, Jacobs, ARUP. Also valuable for PWD, CPWD, and DMRC roles.', 'Structural Engineer, Design Engineer, Bridge Designer, High-Rise Specialist, CAD/STAAD Pro Engineer', 'High demand in both government and private sector projects. Opportunities in metro, highways, bridges, and infrastructure design. Job hubs include Delhi NCR, Mumbai, Hyderabad, Bangalore, and Pune.', 'Fresher: ₹25,000 – ₹40,000/month; Mid-Level: ₹45,000 – ₹65,000/month; Senior: ₹80,000 – ₹1,20,000/month', 'Tata Consulting Engineers, L&T, Bentley India, Gammon India, TCE, AECOM; Apply via AICTE Internship Portal, Internshala, and Bentley Education Portal', 'Junior Structural Engineer → Design Engineer → Lead Structural Consultant → BIM/Structural Manager → Infrastructure/Design Director', 'Bentley STAAD Pro Certified Engineer, Skill-Lync STAAD Pro & Structural Design Certificate, Coursera Structural Design Certificates, AutoCAD + STAAD Pro Combo Certification, NPTEL Structural Engineering Certificate'),
('Engineering', 'Civil Engineering', 'Estimation & Costing', 'IIT Madras, IIT Bombay, IIT Roorkee, IIT Kharagpur, NIT Trichy, NIT Surathkal, BITS Pilani, DTU, COEP Pune, Anna University', 'Quantity Surveying, Construction Economics, Construction Planning & Management, Building Materials & Construction, Estimation Techniques, Contracts and Tenders, Project Cost Control, Construction Accounting', 'Estimating and Costing in Civil Engineering – B.N. Dutta, Quantity Surveying and Valuation – Rangwala, Construction Planning and Management – P.S. Gahlot, Estimating Construction Costs – Robert Peurifoy, Building Materials – S.K. Duggal', 'NPTEL:Estimation and Quantity Surveying, Skill-Lync:Quantity Takeoff and Costing, Coursera:Construction Cost Estimating and Bidding, Udemy:Quantity Surveying Basics, edX:Construction Cost Estimation', 'Civil Guruji:https://www.youtube.com/c/CivilGuruji, Quantity Surveyor Academy:https://www.youtube.com/c/QuantitySurveyorAcademy, The Civil Engineer:https://www.youtube.com/c/TheCivilEngineer, Construction Adda:https://www.youtube.com/c/ConstructionAdda, GATE Academy Civil:https://www.youtube.com/c/TheGateAcademyCivil', 'https://nptel.ac.in, https://skill-lync.com, https://theconstructor.org, https://civilseek.com, https://qslead.com', 'Placement opportunities in L&T, Shapoorji Pallonji, Tata Projects, NBCC, Gammon India, DMRC, and government roles like PWD, CPWD, and Urban Local Bodies. Real estate and infrastructure consultancies also hire actively.', 'Quantity Surveyor, Cost Estimator, Tendering Engineer, Billing Engineer, Project Cost Analyst', 'Growing demand due to infrastructure and smart city projects. High employability in urban and rural development schemes. Job hubs include Delhi NCR, Pune, Hyderabad, Bangalore, and Chennai.', 'Fresher: ₹20,000 – ₹35,000/month; Mid-Level: ₹40,000 – ₹60,000/month; Senior: ₹75,000 – ₹1,10,000/month', 'L&T, Shapoorji Pallonji, Tata Projects, NBCC, AECOM, Simplex Infra; Apply via Internshala, AICTE, and Skill-Lync portals', 'Trainee QS / Estimator → Billing Engineer → Cost Estimator → Senior QS → Contracts Manager / Commercial Head', 'Certified Quantity Surveyor (QSi / RICS), Skill-Lync Quantity Surveying Certificate, AutoCAD + Revit + CostX Certification, Construction Management Certification (Coursera/edX), Certified Professional Estimator (CPE)'),
('Engineering', 'Electrical Engineering', 'Circuit Design', 'IIT Bombay, IIT Madras, IIT Delhi, IIT Kanpur, NIT Trichy, BITS Pilani, IIIT Hyderabad, VIT Vellore, DTU, MIT Pune', 'Network Theory, Electronic Devices & Circuits, Digital Electronics, Analog Electronics, Control Systems, Microprocessors & Microcontrollers, Power Electronics, VLSI Design, Embedded Systems, Electromagnetic Field Theory', 'Microelectronic Circuits by Sedra & Smith, Electronic Devices and Circuit Theory by Boylestad, Digital Design by M. Morris Mano, The Art of Electronics by Paul Horowitz, VLSI Design by K. Lal Kishore, Power Electronics by P.S. Bimbhra', 'NPTEL: Network Theory, Coursera: VLSI CAD, Coursera: Digital Circuits, edX: Embedded Systems (UT Austin), Udemy: PCB & Embedded Systems, MIT OCW: Circuits', 'Neso Academy: https://www.youtube.com/c/NesoAcademy, All About Electronics: https://www.youtube.com/c/ALLABOUTELECTRONICS, Ekeeda: https://www.youtube.com/c/Ekeeda, MIT OCW: https://www.youtube.com/c/MITOCW, GreatScott!: https://www.youtube.com/c/greatscottlab, Paul McWhorter: https://www.youtube.com/c/PaulMcWhorter', 'https://www.allaboutcircuits.com/, https://circuitdigest.com/, https://www.electronics-tutorials.ws/, https://www.geeksforgeeks.org/category/electronics/, https://www.hackster.io/, https://www.edx.org/, https://www.coursera.org/, https://training.ti.com/', 'Top placements in core companies like Texas Instruments, Intel, Qualcomm, STMicroelectronics, NXP. Also PSUs like BHEL, DRDO, ISRO. Roles in embedded, chip design, VLSI, and R&D.', 'Circuit Design Engineer, Hardware Engineer, Embedded Developer, FPGA Designer, VLSI Design Engineer, PCB Design Engineer', 'High demand in electronics, embedded, IoT, automotive, telecom, and aerospace industries. Opportunities available both in India and abroad.', 'Fresher: ₹4-8 LPA, Mid-level (3-5 yrs): ₹10-18 LPA, Senior (10+ yrs): ₹20-35 LPA+, Foreign Jobs: ₹30 LPA – ₹1 Cr+', 'Internships in BSNL, BHEL, NTPC, DRDO, ISRO, Texas Instruments, SmartInternz, Internshala, Embedded startups', 'Circuit Design Engineer → Senior Hardware Designer → Embedded Lead/VLSI Specialist → Tech Lead → Engineering Manager → CTO or Founder', 'Embedded Systems Certification (Coursera, NPTEL), VLSI Design (Cadence, Mentor Graphics), PCB Design (Altium Designer, KiCAD), TI Analog Engineer, MATLAB Certification, IEEE Membership'),
('Engineering', 'Electrical Engineering', 'PLC (Programmable Logic Controllers)', 'IIT Madras, IIT Roorkee, NIT Surathkal, BITS Pilani, VIT Vellore, MIT Pune, SRM University, DTU, COEP Pune, Amrita Vishwa Vidyapeetham', 'Control Systems, Industrial Instrumentation, Digital Electronics, Microcontrollers, Electrical Machines, PLC & SCADA, Process Control, Sensors and Transducers, Embedded Systems', 'Programmable Logic Controllers by Frank D. Petruzella, PLC Programming for Industrial Automation by Kevin Collins, Automation by Mikell P. Groover, Control Systems Engineering by Nagrath & Gopal, Industrial Instrumentation by D. Patranabis', 'NPTEL: Industrial Automation, Udemy: Siemens & Allen Bradley PLC, Coursera: Industrial IoT, LinkedIn Learning: PLC Basics, Skill-Lync: Industrial Automation Specialization', 'Electrical Engineering Portal: https://www.youtube.com/c/ElectricalEngineeringPortal, Sololearn Automation: https://www.youtube.com/c/sololearnautomation, Learn Automation: https://www.youtube.com/c/LearnAutomation1, NPTEL India: https://www.youtube.com/c/nptelhrd, Sanjay Technical Academy: https://www.youtube.com/@sanjaytechnicalacademy', 'https://www.automationdirect.com/, https://plcacademy.com/, https://www.electrical4u.com/, https://nptel.ac.in/, https://scadahacker.com/, https://coursera.org/, https://tiautomation.com/', 'Top placements in Siemens, ABB, Rockwell, Schneider, L&T, Honeywell. Job roles include Automation Engineer, Control System Engineer, SCADA Engineer.', 'PLC Programmer, SCADA Engineer, Industrial Automation Engineer, Control Systems Engineer, Embedded Automation Developer', 'High demand in process industries, automotive, robotics, power plants. International jobs available in Gulf, Europe.', 'Fresher: ₹3.5–6.5 LPA, Mid-level: ₹8–14 LPA, Senior: ₹18–30 LPA, Gulf Jobs: ₹20–45 LPA', 'Internships via L&T, Siemens, NSIC, ABB, BHEL, Skill India, SmartInternz, Internshala', 'PLC Programmer → Automation Engineer → Control Systems Specialist → Project Manager → Automation Architect', 'Siemens TIA Certification, Rockwell PLC Training, ISA Certified Automation Professional (CAP), NPTEL Automation, NSDC PLC Certification'),
