('Science', 'Forensic Science', 'DNA Analysis', '[\"National Institute of Criminology and Forensic Science (NICFS), Delhi\", \"Dr. Harisingh Gour Central University, Sagar\", \"University of Hyderabad, Hyderabad\", \"Institute of Forensic Science, Mumbai\", \"Punjabi University, Patiala\", \"Bundelkhand University, Jhansi\", \"Mahatma Gandhi University, Kerala\", \"Amity University, Noida\", \"Delhi University, Delhi\", \"Guru Ghasidas University, Bilaspur\"]', 'Forensic Biology and Serology, Molecular Biology, Genetics and DNA Technology, Biochemistry, Crime Scene Investigation, Forensic Chemistry, Toxicology, Criminal Law and Procedure', '[\"Forensic DNA Typing – John M. Butler\", \"Principles of Forensic DNA Typing – John M. Butler\", \"Forensic Science in Crime Investigation – B.R. Sharma\", \"Fundamentals of Forensic Science – Max M. Houck and Jay A. Siegel\", \"Introduction to Forensic DNA Analysis – Max M. Houck\"]', '[{\"platform\":\"Coursera\",\"course\":\"DNA Forensics - University of Adelaide\"},{\"platform\":\"FutureLearn\",\"course\":\"Forensic Science and Criminal Justice\"},{\"platform\":\"edX\",\"course\":\"Introduction to Forensic Science\"},{\"platform\":\"Coursera\",\"course\":\"Molecular Biology - Part 1: DNA Replication and Repair\"},{\"platform\":\"Udemy\",\"course\":\"Basics of DNA Analysis\"}]', '[{\"title\":\"Forensic Science Laboratory India\",\"link\":\"https://www.youtube.com/channel/UCwUheGdeZh6X84JZVXcsxLg\"},{\"title\":\"Forensic Science Simplified\",\"link\":\"https://www.youtube.com/c/ForensicScienceSimplified\"},{\"title\":\"The Forensic Tutor\",\"link\":\"https://www.youtube.com/c/TheForensicTutor\"},{\"title\":\"DNA Learning Center\",\"link\":\"https://www.youtube.com/user/forensicscience\"},{\"title\":\"National Geographic - Forensic Files\",\"link\":\"https://www.youtube.com/user/ForensicFiles\"}]', '[\"https://nicfs.gov.in/\", \"http://forensic.gov.in/\", \"https://www.iafsindia.com/\", \"https://www.interpol.int/en/Crimes/Fore