('Science', 'Forensic Science', 'Crime Scene Investigation', '[\"National Institute of Criminology and Forensic Science (NICFS), Delhi\", \"Dr. Harisingh Gour Central University, Sagar\", \"University of Hyderabad, Hyderabad\", \"Institute of Forensic Science, Mumbai\", \"Punjabi University, Patiala\", \"Bundelkhand University, Jhansi\", \"Mahatma Gandhi University, Kerala\", \"Amity University, Noida\", \"Delhi University, Delhi\", \"Guru Ghasidas University, Bilaspur\"]', 'Crime Scene Management and Protocols, Forensic Evidence Collection, Fingerprint Science, Forensic Photography, Trace Evidence Analysis, Bloodstain Pattern Analysis, Forensic Chemistry, Criminal Law and Procedures', '[\"Crime Scene Investigation – B.R. Kalia\", \"Practical Crime Scene Processing and Investigation – Ross M. Gardner\", \"Forensic Science in Crime Investigation – B.R. Sharma\", \"Criminalistics: An Introduction to Forensic Science – Richard Saferstein\", \"Fundamentals of Forensic Science – Max M. Houck & Jay A. Siegel\"]', '[{\"platform\":\"Coursera\",\"course\":\"Crime Scene Investigation\"},{\"platform\":\"edX\",\"course\":\"Introduction to Forensic Science\"},{\"platform\":\"FutureLearn\",\"course\":\"Forensic Science and Criminal Justice\"},{\"platform\":\"Udemy\",\"course\":\"Fingerprint Analysis and Crime Scene Investigation\"},{\"platform\":\"LinkedIn Learning\",\"course\":\"Bloodstain Pattern Analysis Basics\"}]', '[{\"title\":\"NICFS Official\",\"link\":\"https://www.youtube.com/user/nicfsindia\"},{\"title\":\"Forensic Science Simplified\",\"link\":\"https://www.youtube.com/c/ForensicScienceSimplified\"},{\"title\":\"Crime Scene Investigation Tutorials\",\"link\":\"https://www.youtube.com/c/CSItrainings\"},{\"title\":\"The Forensic Tutor\",\"link\":\"https://www.youtube.com/c/TheForensicTutor\"},{\"title\":\"Real Crime Investigation\",\"link\":\"https://www.youtube.com/c/RealCrimeInvestigation\"}]', '[\"https://nicfs.gov.in/\", \"https://cfsl.gov.in/\", \"http://bprd.nic.i