('Science', 'Forensic Science', 'Fingerprinting', '[\"National Institute of Criminology and Forensic Science (NICFS), Delhi\", \"Dr. Harisingh Gour Central University, Sagar\", \"University of Hyderabad, Hyderabad\", \"Institute of Forensic Science, Mumbai\", \"Punjabi University, Patiala\", \"Bundelkhand University, Jhansi\", \"Mahatma Gandhi University, Kerala\", \"Amity University, Noida\", \"Delhi University, Delhi\", \"Guru Ghasidas University, Bilaspur\"]', 'Fingerprint Science and Technology, Forensic Chemistry, Crime Scene Investigation, Forensic Biology, Legal and Ethical Aspects of Forensics, Forensic Photography, Evidence Collection and Preservation, Criminal Law and Procedure', '[\"Fingerprint Detection Techniques – David Ashbaugh\", \"Introduction to Fingerprint Analysis – Mark R. Haworth\", \"Forensic Science in Crime Investigation – B.R. Sharma\", \"Criminalistics: An Introduction to Forensic Science – Richard Saferstein\", \"Fundamentals of Forensic Science – Max M. Houck & Jay A. Siegel\"]', '[{\"platform\":\"Coursera\",\"course\":\"Fingerprint Analysis and Identification\"},{\"platform\":\"edX\",\"course\":\"Introduction to Forensic Science\"},{\"platform\":\"FutureLearn\",\"course\":\"Forensic Science and Criminal Justice\"},{\"platform\":\"Udemy\",\"course\":\"Fingerprinting Basics\"},{\"platform\":\"LinkedIn Learning\",\"course\":\"Crime Scene and Evidence Collection\"}]', '[{\"title\":\"NICFS Official\",\"link\":\"https://www.youtube.com/user/nicfsindia\"},{\"title\":\"Forensic Science Simplified\",\"link\":\"https://www.youtube.com/c/ForensicScienceSimplified\"},{\"title\":\"Fingerprinting Tutorials\",\"link\":\"https://www.youtube.com/c/FingerprintScience\"},{\"title\":\"The Forensic Tutor\",\"link\":\"https://www.youtube.com/c/TheForensicTutor\"},{\"title\":\"Crime Scene Investigation Tutorials\",\"link\":\"https://www.youtube.com/c/CSItrainings\"}]', '[\"https://nicfs.gov.in/\", \"https://cfsl.gov.in/\", \"http://bprd.nic.in/\", \"https://w