('Science', 'Earth Science / Geology', 'Seismic Data Analysis', '[\"Indian Institute of Technology (IIT), Roorkee\", \"Indian Institute of Technology (IIT), Bombay\", \"Indian Institute of Science (IISc), Bangalore\", \"Banaras Hindu University (BHU), Varanasi\", \"Indian School of Mines (IIT Dhanbad)\", \"University of Delhi, Delhi\", \"Jawaharlal Nehru University (JNU), New Delhi\", \"University of Calcutta, Kolkata\", \"National Institute of Technology (NIT), Tiruchirappalli\", \"Birbal Sahni Institute of Palaeosciences, Lucknow\"]', 'Fundamentals of Seismology, Geophysics and Earthquake Physics, Seismic Data Acquisition and Processing, Geophysical Signal Analysis, Geological and Geophysical Interpretation, Reservoir Geophysics, Applied Geophysics and Seismic Exploration, Geostatistics and Data Modeling', '[\"Introduction to Seismology – Peter Shearer\", \"Quantitative Seismology – Keiiti Aki & Paul G. Richards\", \"Exploration Seismology – R.E. Sheriff & L.P. Geldart\", \"The Rock Physics Handbook – Gary Mavko et al.\", \"Seismic Data Analysis – Özdoğan Yilmaz\"]', '[{\"platform\":\"Coursera\",\"course\":\"Seismology and Seismic Data Analysis\"},{\"platform\":\"NPTEL\",\"course\":\"Applied Geophysics\"},{\"platform\":\"Schlumberger Training\",\"course\":\"Seismic Interpretation (Petrel)\"},{\"platform\":\"edX\",\"course\":\"Earthquake Seismology\"},{\"platform\":\"Udemy\",\"course\":\"Geophysical Data Processing\"}]', '[{\"title\":\"Seismic Data Analysis Tutorials\",\"link\":\"https://www.youtube.com/c/SeismicDataAnalysis\"},{\"title\":\"Geophysics Videos\",\"link\":\"https://www.youtube.com/c/GeophysicsVideos\"},{\"title\":\"Schlumberger Software Training\",\"link\":\"https://www.youtube.com/user/SchlumbergerOilfield\"},{\"title\":\"Earth Science Tutorials\",\"link\":\"https://www.youtube.com/c/EarthScienceTutorials\"},{\"title\":\"NPTEL Geology & Geophysics\",\"link\":\"https://www.youtube.com/c/nptelhrd\"}]', '[\"https://www.iitism.ac.in/\", \"https://www.ngr